def test_powerset_includes_all_subsets():
    from source import powerset

    # Test the powerset of [1, 2]
    result = powerset([1, 2])

    # Expected subsets include the empty set, {1}, {2}, and {1, 2}
    expected_subsets = [
        [],       # empty set
        [1],      # {1}
        [2],      # {2}
        [1, 2]   # {1, 2}
    ]

    # Check that the powerset includes all subsets
    assert len(result) == 4, "Powerset should include four subsets: empty set, {1}, {2}, and {1, 2}"
    assert all(subset in result for subset in expected_subsets), "Powerset should include all subsets of [1, 2]"
